// Extrai dados da mensagem Z-API
const body = $input.first().json.body || $input.first().json;

// Ignora mensagens enviadas por mim
if (body.fromMe === true) return [];

// Ignora grupos
if (body.isGroupMsg === true) return [];

// Extrai campos principais
const phone   = String(body.phone || body.from || '').replace(/\D/g, '');
const message = body.message?.conversation
  || body.text?.message
  || body.message?.extendedTextMessage?.text
  || '';
const name    = body.senderName || body.pushName || 'Lead';

if (!phone || !message.trim()) return [];

return [{ json: { phone, message: message.trim(), name } }];

// Carrega e salva histórico de conversa por telefone (memória local)
const staticData = $getWorkflowStaticData('global');
const phone      = $input.first().json.phone;
const message    = $input.first().json.message;
const name       = $input.first().json.name;

const key     = 'hist_' + phone;
const history = staticData[key] || [];

// Adiciona mensagem do lead
history.push({ role: 'user', content: `[${name}]: ${message}` });

// Limita a 20 mensagens (10 trocas)
if (history.length > 20) history.splice(0, history.length - 20);

staticData[key] = history;

return [{ json: { phone, name, message, history, historyKey: key } }];

// Processa resposta do GPT e salva no histórico
const historyKey = $('Carregar Histórico').first().json.historyKey;
const phone      = $('Carregar Histórico').first().json.phone;
const gptBody    = $input.first().json;
const reply      = gptBody.choices?.[0]?.message?.content || 'Desculpe, tive um problema técnico. Pode repetir?';

// Salva resposta do assistente no histórico
const staticData = $getWorkflowStaticData('global');
const history    = staticData[historyKey] || [];
history.push({ role: 'assistant', content: reply });
if (history.length > 20) history.splice(0, history.length - 20);
staticData[historyKey] = history;

return [{ json: { phone, reply } }];

// Se a IA estiver desativada para este número, para o workflow
const aiStatus = $input.first().json;
const histData = $('Carregar Histórico').first().json;

// Se erro na chamada ou aiEnabled=false, para aqui
if (aiStatus.aiEnabled === false) {
  console.log('[SDR] IA desativada para ' + histData.phone + '. Modo manual ativo.');
  return []; // Para o workflow — não envia resposta
}

// Passa os dados do histórico para o próximo node
return [{ json: histData }];
